import React from 'react';
import './home.css';
import logo from './assets/logo.png';
import linkdin from './assets/1.png';

function Home() {
  return (
    <div className="home">
      <div className="image">
        <img className="logo no-select" src={require(logo)} alt="logo" />
        <img className="linkdin no-select" src={require(linkdin)} alt="linkdin" />
      </div>
      <div className="text-container">
        <p className='description no-select'>
          « La donnée devient information, lorsqu&#39;elle permet aux acteurs d’agir et aux décideurs de réduire
          leurs&nbsp;&nbsp; incertitude »
        </p>
        <div className="texte-wrapper no-select">DatAdvice</div>
        <div className="texte-wrapper-2 no-select">Votre expert dans la Data</div>
      </div>
    </div>
  );
}

export default Home;
